<?php declare(strict_types=1);namespace App\Services;final class StreamMetricsService{public function collect(?array $stream):array{$pid=(int)($stream['pid']??0);if($pid<1||!is_dir('/proc/'.$pid))return ['connected'=>false,'cpu'=>0,'memory'=>0,'speed'=>0,'bitrate'=>0,'dropped'=>0,'uptime'=>0];$ps=trim((string)shell_exec('ps -p '.$pid.' -o %cpu=,rss='));[$cpu,$rss]=array_pad(preg_split('/\s+/',trim($ps)),2,0);$log=config('settings.log_directory').'/stream-'.$stream['id'].'.log';$tail=is_file($log)?implode("\n",array_slice(file($log,FILE_IGNORE_NEW_LINES)?:[],-40)):'';preg_match('/speed=\s*([\d.]+)x/',$tail,$speed);preg_match('/bitrate=\s*([\d.]+)kbits/',$tail,$bitrate);preg_match('/drop=\s*(\d+)/',$tail,$drop);return ['connected'=>true,'cpu'=>(float)$cpu,'memory'=>(int)$rss*1024,'speed'=>(float)($speed[1]??0),'bitrate'=>(float)($bitrate[1]??0),'dropped'=>(int)($drop[1]??0),'uptime'=>$stream['started_at']?time()-strtotime($stream['started_at']):0];}}
